/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWCategoriaProdutos-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&GrupHie.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Código") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&GrupHie) EndIf If not (&GrupAnaSin.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Tipo") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case &GrupAnaSin.ToString().Trim() = "A" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "ANALÍTICO"
Case &GrupAnaSin.ToString().Trim() = "S" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "SINTÉTICO"
EndCase EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'GRUPNOMCMP' &GrupNomCmp1.FromString(&GridStateDynamicFilter.Value) If not &GrupNomCmp1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Descrição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&GrupNomCmp1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'GRUPNOMCMP' &GrupNomCmp2.FromString(&GridStateDynamicFilter.Value) If not &GrupNomCmp2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Descrição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&GrupNomCmp2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'GRUPNOMCMP' &GrupNomCmp3.FromString(&GridStateDynamicFilter.Value) If not &GrupNomCmp3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Descrição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&GrupNomCmp3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Descrição Grupo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "NCM" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Dsc." &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Smart"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod GrupHiePadL when &OrderedBy = 1 order GrupHie when &OrderedBy = 2 AND &OrderedDsc = False order (GrupHie) when &OrderedBy = 2 AND &OrderedDsc = True order GrupNomCmp when &OrderedBy = 3 AND &OrderedDsc = False order (GrupNomCmp) when &OrderedBy = 3 AND &OrderedDsc = True order GrupAnaSin when &OrderedBy = 4 AND &OrderedDsc = False order (GrupAnaSin) when &OrderedBy = 4 AND &OrderedDsc = True order GrupNCM when &OrderedBy = 5 AND &OrderedDsc = False order (GrupNCM) when &OrderedBy = 5 AND &OrderedDsc = True order GrupDscMax when &OrderedBy = 6 AND &OrderedDsc = False order (GrupDscMax) when &OrderedBy = 6 AND &OrderedDsc = True order GrupSmt when &OrderedBy = 7 AND &OrderedDsc = False order (GrupSmt) when &OrderedBy = 7 AND &OrderedDsc = True
using DSWWCategoriaProdutos(&GrupHie, &DynamicFiltersSelector1, &GrupNomCmp1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &GrupNomCmp2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &GrupNomCmp3, &GrupAnaSin)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(GrupHie) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(GrupNomCmp) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = '' do Case Case GrupAnaSin.ToString().Trim() = "A" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "ANALÍTICO"
Case GrupAnaSin.ToString().Trim() = "S" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "SINTÉTICO"
EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = GrupNCM &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Number = GrupDscMax &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = GrupSmt.ToString()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWCategoriaProdutosGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWCategoriaProdutosGridState")) Else &GridState.FromXml(&Session.Get(!"WWCategoriaProdutosGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"GRUPHIE" &GrupHie.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"GRUPANASIN" &GrupAnaSin.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

